#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::Table;
use Date::Manip;

sub extract_info {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Extract the first page and its text
    my $page = $pdf->openpage(1);
    my $text = $page->text();

    # Look for specific text patterns
    my ($author, $date, $table_info);

    if ($text =~ /Author:\s*(.*?)\n/) {
        $author = $1;
    }

    if ($text =~ /Date:\s*(.*?)\n/) {
        $date = $1;
        $date = parse_date($date);
    }

    # Extract tables
    $table_info = PDF::Table->new($pdf_file, 1);

    return ($author, $date, $table_info);
}

sub parse_date {
    my ($date) = @_;
    return UnixDate(ParseDate($date), "%Y-%m-%d");
}

sub main {
    my $pdf_file = shift || die "Usage: perl pdf_looter.pl <pdf_file>\n";
    my ($author, $date, $table_info) = extract_info($pdf_file);

    print "Author: $author\n";
    print "Date: $date\n";
    print "Table Information: $table_info\n";
}

main();
